// // This module selects between two 32-bit wide inputs based on the aluSRC signal. When aluSRC is 0, the output is the value of sing_ext1, and when aluSRC is 1, the output is the value of data0.
module top_module(
	input [31:0]sing_ext1,
	input [31:0]data0,
	input aluSRC,
	output [31:0]salida

);assign
	salida = (aluSRC)? sing_ext1 : data0;

endmodule
